import{_ as t,o as a,c as e,a4 as d}from"./chunks/framework.BMymQDdR.js";const u=JSON.parse('{"title":"日志控制台","description":"","frontmatter":{},"headers":[],"relativePath":"v3/designer/Log-Console.md","filePath":"zh/v3/designer/Log-Console.md","lastUpdated":1780630099000}'),r={name:"v3/designer/Log-Console.md"},o=d('<h1 id="日志控制台" tabindex="-1">日志控制台 <a class="header-anchor" href="#日志控制台" aria-label="Permalink to &quot;日志控制台&quot;">​</a></h1><p>日志控制台位于设计器底部，用于显示设计器运行日志、构建输出、预览运行信息等。</p><h2 id="界面说明" tabindex="-1">界面说明 <a class="header-anchor" href="#界面说明" aria-label="Permalink to &quot;界面说明&quot;">​</a></h2><p>日志控制台采用语法高亮编辑器（SynEdit），支持：</p><ul><li>只读模式 - 仅显示日志，不可直接编辑</li><li>时间戳 - 每条日志自动添加时间戳 <code>[HH:MM:SS.sss]</code></li><li>语法高亮 - 按日志级别显示不同颜色</li><li>自动滚动 - 新日志添加后自动滚动到底部</li></ul><h2 id="日志级别" tabindex="-1">日志级别 <a class="header-anchor" href="#日志级别" aria-label="Permalink to &quot;日志级别&quot;">​</a></h2><table tabindex="0"><thead><tr><th>级别</th><th>颜色</th><th>说明</th></tr></thead><tbody><tr><td>ERROR</td><td>红色</td><td>错误信息，需要关注</td></tr><tr><td>WARN</td><td>蓝色</td><td>警告信息，可能存在潜在问题</td></tr><tr><td>INFO</td><td>绿色</td><td>普通信息，如构建开始/结束、运行状态</td></tr><tr><td>DEBUG</td><td>灰色</td><td>调试信息，开发调试用</td></tr></tbody></table><h2 id="右键菜单" tabindex="-1">右键菜单 <a class="header-anchor" href="#右键菜单" aria-label="Permalink to &quot;右键菜单&quot;">​</a></h2><p>在日志控制台中 <strong>右键</strong> 弹出上下文菜单：</p><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td>复制</td><td>复制选中的日志文本</td></tr><tr><td>全选</td><td>选中所有日志文本</td></tr><tr><td>清空</td><td>清空所有日志内容</td></tr></tbody></table><h2 id="日志来源" tabindex="-1">日志来源 <a class="header-anchor" href="#日志来源" aria-label="Permalink to &quot;日志来源&quot;">​</a></h2><p>日志控制台接收以下来源的输出：</p><ul><li><strong>设计器日志</strong> - 设计器自身的运行日志</li><li><strong>构建输出</strong> - 项目编译过程的输出</li><li><strong>运行输出</strong> - 预览运行时的应用输出</li><li><strong>事件系统</strong> - 各模块通过事件系统发送的消息</li></ul><h2 id="日志限制" tabindex="-1">日志限制 <a class="header-anchor" href="#日志限制" aria-label="Permalink to &quot;日志限制&quot;">​</a></h2><p>为防止内存占用过大，日志控制台自动限制最大行数为 500 行。超过限制时，最早的日志会被自动删除。</p>',15),l=[o];function i(n,s,h,c,_,b){return a(),e("div",null,l)}const g=t(r,[["render",i]]);export{u as __pageData,g as default};
